1948 /// Remove negation and try to reassociate constant math.
1949 static Instruction *foldFDivConstantDividend(BinaryOperator &I) {
1950   Constant *C;
1951   if (!match(I.getOperand(0), m_Constant(C)))
1952     return nullptr;
1953 
1954   // C / -X --> -C / X
1955   Value *X;
1956   const DataLayout &DL = I.getDataLayout();
1957   if (match(I.getOperand(1), m_FNeg(m_Value(X))))
1958     if (Constant *NegC = ConstantFoldUnaryOpOperand(Instruction::FNeg, C, DL))
1959       return BinaryOperator::CreateFDivFMF(NegC, X, &I);
1960 
1961   if (!I.hasAllowReassoc() || !I.hasAllowReciprocal())
1962     return nullptr;
1963 
1964   // Try to reassociate C / X expressions where X includes another constant.
1965   Constant *C2, *NewC = nullptr;
1966   if (match(I.getOperand(1), m_FMul(m_Value(X), m_Constant(C2)))) {
1967     // C / (X * C2) --> (C / C2) / X
1968     NewC = ConstantFoldBinaryOpOperands(Instruction::FDiv, C, C2, DL);
1969   } else if (match(I.getOperand(1), m_FDiv(m_Value(X), m_Constant(C2)))) {
1970     // C / (X / C2) --> (C * C2) / X
1971     NewC = ConstantFoldBinaryOpOperands(Instruction::FMul, C, C2, DL);
1972   }
1973   // Disallow denormal constants because we don't know what would happen
1974   // on all targets.
1975   // TODO: Use Intrinsic::canonicalize or let function attributes tell us that
1976   // denorms are flushed?
1977   if (!NewC || !NewC->isNormalFP())
1978     return nullptr;
1979 
1980   return BinaryOperator::CreateFDivFMF(NewC, X, &I);
1981 }
