2036   auto *II = dyn_cast<IntrinsicInst>(Op1);
2037   if (!II || II->getIntrinsicID() != Intrinsic::sqrt || !II->hasOneUse() ||
2038       !II->hasAllowReassoc() || !II->hasAllowReciprocal())
2039     return nullptr;
