3572 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3573                                                FPClassTest DemandedMask,
3574                                                KnownFPClass &Known,
3575                                                unsigned Depth) {
3576   Use &U = I->getOperandUse(OpNo);
3577   Value *V = U.get();
3578   Type *VTy = V->getType();
3579 
3580   if (DemandedMask == fcNone) {
3581     if (isa<PoisonValue>(V))
3582       return false;
3583     replaceUse(U, PoisonValue::get(VTy));
3584     return true;
3585   }
3586 
3587   // Handle constant
3588   Instruction *VInst = dyn_cast<Instruction>(V);
3589   if (!VInst) {
3590     // Handle constants and arguments
3591     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3592     Known.knownNot(~DemandedMask);
3593 
3594     if (Known.KnownFPClasses == fcNone) {
3595       if (isa<PoisonValue>(V))
3596         return false;
3597       replaceUse(U, PoisonValue::get(VTy));
3598       return true;
3599     }
3600 
3601     // Do not try to replace values which are already constants (unless we are
3602     // folding to poison). Doing so could promote poison elements to non-poison
3603     // constants.
3604     if (isa<Constant>(V))
3605       return false;
3606 
3607     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3608     if (!FoldedToConst || FoldedToConst == V)
3609       return false;
3610 
3611     replaceUse(U, FoldedToConst);
3612     return true;
3613   }
3614 
3615   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3616     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3617     DemandedMask &= ~NoFPClass;
3618   }
3619 
3620   if (Depth == MaxAnalysisRecursionDepth) {
3621     Known.knownNot(~DemandedMask);
3622     return false;
3623   }
3624 
3625   Value *NewVal;
3626 
3627   if (VInst->hasOneUse()) {
3628     // If the instruction has one use, we can directly simplify it.
3629     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3630   } else {
3631     // If there are multiple uses of this instruction, then we can simplify
3632     // VInst to some other value, but not modify the instruction.
