309   void copysign(const KnownFPClass &Sign) {
310     // Don't know anything about the sign of the source. Expand the possible set
311     // to its opposite sign pair.
312     if (KnownFPClasses & fcZero)
313       KnownFPClasses |= fcZero;
314     if (KnownFPClasses & fcSubnormal)
315       KnownFPClasses |= fcSubnormal;
316     if (KnownFPClasses & fcNormal)
317       KnownFPClasses |= fcNormal;
318     if (KnownFPClasses & fcInf)
319       KnownFPClasses |= fcInf;
320 
321     // Sign bit is exactly preserved even for nans.
322     SignBit = Sign.SignBit;
323 
324     // Clear sign bits based on the input sign mask.
325     if (Sign.isKnownNever(fcPositive | fcNan) || (SignBit && *SignBit))
326       KnownFPClasses &= (fcNegative | fcNan);
327     if (Sign.isKnownNever(fcNegative | fcNan) || (SignBit && !*SignBit))
328       KnownFPClasses &= (fcPositive | fcNan);
329   }
330 
331   static KnownFPClass copysign(const KnownFPClass &KnownMag,
332                                const KnownFPClass &KnownSign) {
333     KnownFPClass Known = KnownMag;
334     Known.copysign(KnownSign);
335     return Known;
336   }
