338   // Propagate knowledge that a non-NaN source implies the result can also not
339   // be a NaN. For unconstrained operations, signaling nans are not guaranteed
340   // to be quieted but cannot be introduced.
341   void propagateNaN(const KnownFPClass &Src, bool PreserveSign = false) {
342     if (Src.isKnownNever(fcNan)) {
343       knownNot(fcNan);
344       if (PreserveSign)
345         SignBit = Src.SignBit;
346     } else if (Src.isKnownNever(fcSNan))
347       knownNot(fcSNan);
348   }
